// Flora Business Data Bridge: 인증 + 쿼리 라우팅
const body = $input.first().json.body;
const chatId = String(body.chat_id || '');
const queryType = (body.query_type || '').toLowerCase();

// 인증
const ALLOWED = ['7713811206', '8606163783'];
if (!ALLOWED.includes(chatId)) {
  return [{ json: { error: true, message: '권한 없음' } }];
}

// 쿼리 타입 매핑
const QUERIES = {
  'sales': {
    table: 'mddg3t3fft6uh2q',
    label: '주간 매출',
    sort: '-week',
    limit: 4,
    fields: 'week,total_orders,total_revenue,avg_order_value'
  },
  'segments': {
    table: 'mg2coommaxsyfmf',
    label: '고객 세그먼트',
    sort: '-total_spent',
    limit: 100,
    fields: 'user_id,user_name,segment,order_count,total_spent,recency_days'
  },
  'campaigns': {
    table: 'ma92big019irvlt',
    label: '캠페인 발송',
    sort: '-sent_at',
    limit: 20,
    fields: 'user_id,user_name,segment,phone,status,sent_at'
  },
  'partners': {
    table: 'mcafm2yyeaupdnt',
    label: '파트너 현황',
    sort: '-UpdatedAt',
    limit: 50,
    fields: 'partner_name,grade,status,class_count'
  }
};

// 자연어 → 쿼리 타입 매핑
let resolved = queryType;
if (!QUERIES[resolved]) {
  if (queryType.includes('매출') || queryType.includes('주문') || queryType.includes('sales')) resolved = 'sales';
  else if (queryType.includes('고객') || queryType.includes('세그먼트') || queryType.includes('rfm')) resolved = 'segments';
  else if (queryType.includes('캠페인') || queryType.includes('발송') || queryType.includes('sms')) resolved = 'campaigns';
  else if (queryType.includes('파트너') || queryType.includes('강사')) resolved = 'partners';
  else {
    return [{ json: { error: true, message: '지원 쿼리: sales(매출), segments(고객), campaigns(캠페인), partners(파트너)' } }];
  }
}

const q = QUERIES[resolved];
return [{ json: { error: false, queryType: resolved, ...q } }];

// 결과를 플로라가 읽기 쉬운 형태로 포맷
const authData = $('Auth & Route').first().json;
const nocoResp = $input.first().json;
const rows = nocoResp.list || [];
const queryType = authData.queryType;
const label = authData.label;

let summary = '';

if (queryType === 'sales') {
  summary = '📊 ' + label + ' (최근 ' + rows.length + '주)\n';
  for (const r of rows) {
    summary += '  ' + (r.week || '?') + ': 주문 ' + (r.total_orders || 0) + '건, 매출 ' + Number(r.total_revenue || 0).toLocaleString() + '원\n';
  }
} else if (queryType === 'segments') {
  const segCount = {};
  for (const r of rows) {
    const s = r.segment || '미분류';
    segCount[s] = (segCount[s] || 0) + 1;
  }
  summary = '👥 ' + label + ' (총 ' + rows.length + '명)\n';
  for (const [s, c] of Object.entries(segCount).sort((a,b) => b[1]-a[1])) {
    summary += '  ' + s + ': ' + c + '명\n';
  }
} else if (queryType === 'campaigns') {
  summary = '📨 ' + label + ' (최근 ' + rows.length + '건)\n';
  for (const r of rows.slice(0, 10)) {
    summary += '  ' + (r.user_name || '?') + ' | ' + (r.segment || '?') + ' | ' + (r.status || '?') + ' | ' + (r.sent_at || '?').substring(0, 10) + '\n';
  }
} else if (queryType === 'partners') {
  summary = '🤝 ' + label + ' (총 ' + rows.length + '명)\n';
  const gradeCount = {};
  for (const r of rows) {
    const g = r.grade || '미분류';
    gradeCount[g] = (gradeCount[g] || 0) + 1;
  }
  for (const [g, c] of Object.entries(gradeCount).sort((a,b) => b[1]-a[1])) {
    summary += '  ' + g + ': ' + c + '명\n';
  }
}

return [{ json: { success: true, queryType, label, count: rows.length, summary, data: rows.slice(0, 20) } }];
